1	//! Clipboard helpers for `panopt _viewer`.
2	//!
3	//! Three strategies, tried in order by [`copy_to_clipboard`]:
4	//!
5	//! 1. **Zellij plugin pipe**. Inside the cockpit we ship the text to the
6	//!    `panopt-zellij` plugin via `zellij action pipe -- <text>`; the
7	//!    plugin then calls Zellij's host `copy_to_clipboard` API. The
8	//!    plugin holds the `WriteToClipboard` permission (pre-granted by
9	//!    `up::ensure_clipboard_permission_granted`), so Zellij does whatever
10	//!    the user's clipboard config asks - including emitting OSC 52 to the
11	//!    host terminal end-to-end with no intermediate layer eating it.
12	//!    This is the path that actually works for the SSH'd-into-a-host case.
13	//! 2. **External command** (`pbcopy` / `wl-copy` / `xclip` / `xsel`).
14	//!    Useful when we're not inside Zellij (a stand-alone `panopt _viewer`
15	//!    for tests / hacks) and a local clipboard daemon is reachable.
16	//! 3. **OSC 52** (`\x1b]52;c;<base64>\x07`), raw to stdout, with tmux
17	//!    DCS pass-through when `$TMUX` is set. Last-resort fallback.
18	
19	use std::io::{self, Write};
20	use std::process::{Command, Stdio};
21	
22	/// Encode `bytes` in the standard `A-Z a-z 0-9 + /` base64 alphabet with `=`
23	/// padding. Hand-rolled rather than pulled in as a crate dependency; OSC 52
24	/// is the only use site and the encoder is twenty lines.
25	fn base64_encode(bytes: &[u8]) -> String {
26	    const ALPHABET: &[u8; 64] = b"REDACTED/";
27	    let mut out = String::with_capacity(bytes.len().div_ceil(3) * 4);
28	    for chunk in bytes.chunks(3) {
29	        let b0 = chunk[0];
30	        let b1 = chunk.get(1).copied().unwrap_or(0);
31	        let b2 = chunk.get(2).copied().unwrap_or(0);
32	        out.push(ALPHABET[(b0 >> 2) as usize] as char);
33	        out.push(ALPHABET[(((b0 & 0x03) << 4) | (b1 >> 4)) as usize] as char);
34	        if chunk.len() >= 2 {
35	            out.push(ALPHABET[(((b1 & 0x0f) << 2) | (b2 >> 6)) as usize] as char);
36	        } else {
37	            out.push('=');
38	        }
39	        if chunk.len() >= 3 {
40	            out.push(ALPHABET[(b2 & 0x3f) as usize] as char);
41	        } else {
42	            out.push('=');
43	        }
44	    }
45	    out
46	}
47	
48	/// Build the OSC 52 escape sequence carrying `text`. The `c` selector targets
49	/// the system clipboard (as opposed to a primary / secondary buffer); the
50	/// `\x07` terminator is the form every terminal emulator we care about
51	/// accepts (older docs also show `\x1b\\` ST, but `\x07` BEL is universal).
52	pub(crate) fn to_osc52(text: &str) -> String {
53	    format!("\x1b]52;c;{}\x07", base64_encode(text.as_bytes()))
54	}
55	
56	/// Wrap an OSC 52 sequence (or any escape sequence) in tmux's DCS
57	/// pass-through envelope when we appear to be running inside tmux. The
58	/// wrapper is `ESC P tmux; ESC <payload> ESC \\`; tmux strips the leading
59	/// `ESC P tmux;` and trailing `ESC \\`, doubles the inner `ESC` back to a
60	/// single one, and forwards the rest to its own parent terminal. Requires
61	/// `set -g allow-passthrough on` in the user's tmux config (off by default
62	/// in tmux 3.3+).
63	///
64	/// Detection uses `$TMUX`, which tmux exports for every process it spawns.
65	/// Outside tmux the payload is returned unchanged.
66	fn wrap_for_tmux(payload: &str) -> String {
67	    if std::env::var_os("TMUX").is_none() {
68	        return payload.to_string();
69	    }
70	    // Inside tmux the payload's own ESCs would be eaten when tmux strips
71	    // its DCS wrapper; double them so one survives the strip.
72	    let escaped = payload.replace('\x1b', "\x1b\x1b");
73	    format!("\x1bPtmux;{escaped}\x1b\\")
74	}
75	
76	/// Write the OSC 52 sequence for `text` straight to stdout. The viewer holds
77	/// the terminal in raw alt-screen mode, so crossterm does not intercept the
78	/// bytes; they pass through Zellij and the host terminal forwards them to
79	/// the system clipboard *if* OSC 52 is allowed end-to-end. Zellij's stock
80	/// behaviour is to intercept the sequence instead of forwarding it - which
81	/// is why this is a fallback, not the primary path. See
82	/// [`copy_to_clipboard`] for the actual entry point.
83	///
84	/// When `$TMUX` is set the sequence is also wrapped in a DCS pass-through
85	/// envelope so tmux forwards it up to the next layer (Zellij forwards DCS
86	/// strings by default, and tmux strips the wrapper on its way out). Users
87	/// who want this chain to work need `set -g allow-passthrough on` in their
88	/// tmux config; otherwise tmux drops the DCS pass-through.
89	pub(crate) fn emit_osc52(text: &str) -> io::Result<()> {
90	    let seq = wrap_for_tmux(&to_osc52(text));
91	    let mut out = io::stdout();
92	    out.write_all(seq.as_bytes())?;
93	    out.flush()
94	}
95	
96	/// Try each candidate clipboard daemon command, in priority order, until one
97	/// accepts the payload. Returns `true` as soon as a child exits successfully.
98	///
99	/// Order: macOS first (`pbcopy`), then Wayland (`wl-copy`), then X11
100	/// (`xclip` then `xsel`). The `wl-copy` order before X11 matters because
101	/// systems that run both XWayland and Wayland natively often have both
102	/// `xclip` and `wl-copy` installed but only the latter actually reaches the
103	/// running compositor's clipboard.
104	fn copy_via_external_command(text: &str) -> bool {
105	    let candidates: &[(&str, &[&str])] = &[
106	        ("pbcopy", &[]),
107	        ("wl-copy", &[]),
108	        ("xclip", &["-selection", "clipboard"]),
109	        ("xsel", &["--clipboard", "--input"]),
110	    ];
111	    for &(cmd, args) in candidates {
112	        let Ok(mut child) = Command::new(cmd)
113	            .args(args)
114	            .stdin(Stdio::piped())
115	            .stdout(Stdio::null())
116	            .stderr(Stdio::null())
117	            .spawn()
118	        else {
119	            continue;
120	        };
121	        // Take stdin so dropping it closes the pipe and the child sees EOF;
122	        // without that close `wl-copy --foreground` (and friends) would
123	        // wait forever.
124	        if let Some(mut stdin) = child.stdin.take() {
125	            if stdin.write_all(text.as_bytes()).is_err() {
126	                let _ = child.kill();
127	                continue;
128	            }
129	        }
130	        if let Ok(status) = child.wait() {
131	            if status.success() {
132	                return true;
133	            }
134	        }
135	    }
136	    false
137	}
138	
139	/// Ship the text to the `panopt-zellij` plugin via `zellij action pipe`.
140	/// The plugin then calls Zellij's host `copy_to_clipboard` API, which
141	/// respects the user's `copy_command` / `copy_clipboard` config and emits
142	/// OSC 52 to the parent terminal where appropriate - Zellij's
143	/// cross-layer clipboard story, end-to-end.
144	///
145	/// Skipped (returns false) when `$ZELLIJ` is unset; we are running outside
146	/// the cockpit and the spawn would fail anyway.
147	fn copy_via_zellij_plugin(text: &str) -> bool {
148	    if std::env::var_os("ZELLIJ").is_none() {
149	        return false;
150	    }
151	    let Ok(status) = Command::new("zellij")
152	        .args([
153	            "action",
154	            "pipe",
155	            "--name",
156	            "panopt:copy-to-clipboard",
157	            "--plugin-configuration",
158	            "mode=todos",
159	            "--",
160	            text,
161	        ])
162	        .stdin(Stdio::null())
163	        .stdout(Stdio::null())
164	        .stderr(Stdio::null())
165	        .status()
166	    else {
167	        return false;
168	    };
169	    status.success()
170	}
171	
172	/// Put `text` in the system clipboard. Tries every path that might work,
173	/// not just the first one that returns success - the failure modes of each
174	/// path are silent (a clipboard daemon may exit 0 without actually writing
175	/// to a session-less compositor; a Zellij pipe spawn may succeed without
176	/// the plugin's host call reaching the host terminal). The user's
177	/// clipboard ends up with the text as soon as *any* path actually lands
178	/// it, so running every path is cheaper than diagnosing which one is
179	/// silently broken in their setup.
180	pub(crate) fn copy_to_clipboard(text: &str) -> io::Result<()> {
181	    log_copy_request(text);
182	    // Cheapest path first: a direct OSC 52 to our own stdout. Zellij sees
183	    // the bytes and decides whether to forward them to the host terminal
184	    // or eat them; users with a working OSC-52 chain (most modern setups)
185	    // get their clipboard here. Wrapped in tmux DCS pass-through when
186	    // `$TMUX` is set.
187	    let osc52_result = emit_osc52(text);
188	    // Plugin pipe path: ships the text to `panopt-zellij`'s pipe handler,
189	    // which calls Zellij's host `copy_to_clipboard` (separate code path
190	    // from raw OSC-52 forwarding in Zellij).
191	    let _ = copy_via_zellij_plugin(text);
192	    // External daemon for the non-Zellij dev cases.
193	    let _ = copy_via_external_command(text);
194	    osc52_result
195	}
196	
197	/// Append a diagnostic line to the cockpit's copy-debug log alongside the
198	/// helper script's own log entries, so a mismatch between "what the viewer
199	/// asked to copy" and "what the script saw on stdin" points at the
200	/// corruption layer. Silent on any write failure (debug, not load-bearing).
201	fn log_copy_request(text: &str) {
202	    let Some(path) = crate::paths::copy_debug_log().ok() else {
203	        return;
204	    };
205	    let line = format!(
206	        "=== viewer copy_to_clipboard pid={pid} bytes={bytes} ===\nviewer body: {head:?}\n",
207	        pid = std::process::id(),
208	        bytes = text.len(),
209	        head = &text.chars().take(200).collect::<String>(),
210	    );
211	    let _ = std::fs::OpenOptions::new()
212	        .create(true)
213	        .append(true)
214	        .open(&path)
215	        .and_then(|mut f| f.write_all(line.as_bytes()));
216	}
