// PANopt cockpit Zellij config - generated by `panopt up`, regenerated
// each run from your own Zellij config. Zellij's Ctrl-S (scroll mode)
// is remapped to Ctrl-Shift-S so a bare Ctrl-S reaches panes: the todo
// form (`panopt todo edit`) saves on it. Alt-N is retargeted to pipe
// a `panopt:spawn-blank-pane` message to the sidebar plugin, which
// spawns a blank viewer pane with its own routing slot. CloseFocus,
// CloseTab, and Quit are retargeted to pipe close-request messages to
// the sidebar, which gates them against active agents/commands/terminals.
// `mouse_mode true` is forced so the auto-locked input mode (set by
// the plugin when focus lands on a content pane) doesn't strand the
// user without mouse events reaching the viewer / terminal panes.
// Alt-arrow pane navigation plus the rewritten Alt-N and Ctrl-Q are
// spliced into the existing `locked` block (a second top-level
// `keybinds` block does not work - Zellij only reads the first one),
// so the user can leave a content pane, spawn a new one, or quit
// without a Ctrl-G escape that would just be re-locked on the next
// PaneUpdate. PageUp / PageDown go into a `shared { ... }` block
// so they hit ScrollUp/ScrollDown directly in every mode - the
// pane's Zellij scrollback scrolls and auto-returns on next I/O,
// and the keys never reach the inner program.
//
// THIS FILE WAS AUTOGENERATED BY ZELLIJ, THE PREVIOUS FILE AT THIS LOCATION WAS COPIED TO: /home/gregz/.config/zellij/config.kdl.bak
//

keybinds clear-defaults=true {
    locked {
        bind "Ctrl g" { SwitchToMode "normal"; }
            bind "Alt Left" { MoveFocusOrTab "Left"; }
        bind "Alt Right" { MoveFocusOrTab "Right"; }
        bind "Alt Up" { MoveFocus "Up"; }
        bind "Alt Down" { MoveFocus "Down"; }
        bind "Alt n" { Run "zellij" "action" "pipe" "--name" "panopt:spawn-blank-pane" "--plugin-configuration" "mode=todos" { close_on_exit true; }; }
        bind "Ctrl q" { Run "zellij" "action" "pipe" "--name" "panopt:quit-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; }
    }
    pane {
        bind "left" { MoveFocus "left"; }
        bind "down" { MoveFocus "down"; }
        bind "up" { MoveFocus "up"; }
        bind "right" { MoveFocus "right"; }
        bind "c" { SwitchToMode "renamepane"; PaneNameInput 0; }
        bind "d" { NewPane "down"; SwitchToMode "normal"; }
        bind "e" { TogglePaneEmbedOrFloating; SwitchToMode "normal"; }
        bind "f" { ToggleFocusFullscreen; SwitchToMode "normal"; }
        bind "h" { MoveFocus "left"; }
        bind "i" { TogglePanePinned; SwitchToMode "normal"; }
        bind "j" { MoveFocus "down"; }
        bind "k" { MoveFocus "up"; }
        bind "l" { MoveFocus "right"; }
        bind "n" { NewPane; SwitchToMode "normal"; }
        bind "p" { SwitchFocus; }

